  const MOTS_EXPERT = ["Abscons", "Acédie", "Bathos", "Casuistique", "Circumlocution", "Déférence", "Gnose", "Immanent", "Lénifier", "Outrecuidance", "Palimpseste", "Quintessence", "Ratiociner", "Sibyllin", "Sycophante", "Uxoricité", "Zélateur", "aliénation", "amnistie", "analepse", "aporie", "arbitrage", "autocrate", "biomécanique", "blitzkrieg", "chaos déterministe", "chiaroscuro", "chiasme", "cinesthésie", "collage", "contractualisme", "dialectique matérialiste", "dressage", "déconstructivisme", "dépassement de soi", "ekphrasis", "endémisme", "enjeu tactique", "entropie", "facétieux", "fractale", "fugue", "gastronomie moléculaire", "géotropisme", "gérrymandring", "homéostasie", "immanence", "inachevé", "indigence", "inertie", "ironie socratique", "julienne", "lithosphère", "lobbyisme", "mansuétude", "millefeuille", "mirepoix", "mise en abyme", "mutation génétique", "mécanique quantique", "narrateur hétérodiégétique", "ontologie", "ostentation", "paratexte", "phototropisme", "phénoménologie", "plasticité musculaire", "pogrom", "polyphonie narrative", "proprioception", "prosopopée", "prérogative", "quark", "ready-made", "relativity", "réaction de Maillard", "réalpolitik", "sfumato", "subduction", "suffragette", "séquençage génomique", "tacite", "technocratie", "terrine", "terroir", "terroir viticole", "tondo", "totalitarisme", "transpiration végétale", "trophisme", "universaux", "valence", "volcanisme", "volonté de puissance", "volée", "zeste", "épiphyte", "équation différentielle", "état d'exception", "œuvre d'art totale"]

  const EXPRESSIONS_NOVICE = ["D'une pierre deux coups", "Avoir le cafard", "Les carottes sont cuites", "Jeter de la poudre aux yeux", "Mettre de l'eau dans son vin", "Noyer le poisson", "Jeter l'éponge", "Mordre la poussière", "Ne pas vendre la peau de l'ours", "Couper l'herbe sous le pied", "Battre le fer pendant qu'il est chaud", "Vendre la mèche", "Avoir la tête dans les nuages", "Tomber dans les pommes", "Mettre les pieds dans le plat", "Se lever du pied gauche", "Donner sa langue au chat", "Porter le chapeau", "Avoir d'autres chats à fouetter", "Faire la fine bouche"]
  const EXPRESSIONS_INTERMEDIAIRE = ["Chercher midi à quatorze heures", "Pédaler dans la choucroute", "Ménager la chèvre et le chou", "Tirer les marrons du feu", "Prêcher dans le désert", "Avoir voix au chapitre", "Tirer à hue et à dia", "Avoir maille à partir", "Tourner autour du pot", "Faire flèche de tout bois", "Rompre une lance", "Yeux de Chimène", "Passer le Rubicon", "Être dans de beaux draps", "Revenons à nos moutons", "Jeter le bébé avec l'eau du bain", "Couper la poire en deux", "Avoir le beurre et l'argent du beurre", "Avoir le bras long", "Mettre la charrue avant les bœufs"]
  const EXPRESSIONS_EXPERT = ["Brûler ses vaisseaux", "Tomber de Charybde en Scylla", "Jeter des perles aux pourceaux", "Trancher le nœud gordien", "Ouvrir la boîte de Pandore", "Avoir un fil d'Ariane", "Être le talon d'Achille", "Construire sur du sable", "Cheval de Troie", "Épée de Damoclès", "Lit de Procuste", "Sisyphe au rocher", "Victoire à la Pyrrhus", "Etre dans les bras de Morphée", "Semer des graines de discorde", "Tenir le gouvernail", "Porter sa croix", "Tuer dans l'œuf", "Avoir des yeux derrière la tête", "Mener quelqu'un en bateau"]

  const pool = categoriesPreferees.length >= 3 ? categoriesPreferees : TOUTES_CATEGORIES
  const catsShuffle = [...pool].sort(() => (Math.sin(joursEcoules) * 10000) % 1 - 0.5)
  const troisCats = catsShuffle.slice(0, 3)

  const mots = troisCats.map((cat: string, i: number) => {
    let motsCategorie = BANQUE_MOTS.filter((m: any) => m.theme === cat && m.type === 'mot')
    if (niveauParam === 'novice') {
      const filtres = motsCategorie.filter((m: any) => MOTS_NOVICE.includes(m.mot))
      if (filtres.length > 0) motsCategorie = filtres
    } else if (niveauParam === 'intermediaire') {
      const filtres = motsCategorie.filter((m: any) => MOTS_INTERMEDIAIRE.includes(m.mot))
      if (filtres.length > 0) motsCategorie = filtres
    } else if (niveauParam === 'expert') {
      const filtres = motsCategorie.filter((m: any) => MOTS_EXPERT.includes(m.mot))
      if (filtres.length > 0) motsCategorie = filtres
    }
    if (motsCategorie.length === 0) return { ...BANQUE_MOTS[i % BANQUE_MOTS.length], date: today }
    const idx = (joursEcoules + i * 7) % motsCategorie.length
    return { ...motsCategorie[idx], date: today }
  })

  // Expression filtrée par niveau
  let expressions = BANQUE_MOTS.filter((m: any) => m.type === 'expression')
  if (niveauParam === 'novice') {
    const filtres = expressions.filter((m: any) => EXPRESSIONS_NOVICE.includes(m.mot))
    if (filtres.length > 0) expressions = filtres
  } else if (niveauParam === 'intermediaire') {
    const filtres = expressions.filter((m: any) => EXPRESSIONS_INTERMEDIAIRE.includes(m.mot))
    if (filtres.length > 0) expressions = filtres
  } else if (niveauParam === 'expert') {
    const filtres = expressions.filter((m: any) => EXPRESSIONS_EXPERT.includes(m.mot))
    if (filtres.length > 0) expressions = filtres
  }
  const expr = expressions[joursEcoules % expressions.length]
  mots[2] = { ...expr, date: today }

  return res.status(200).json(mots)
